const msg = $('setarInfo1').first().json.mensagem_lead || '';
const resumo = $input.first().json.observacoes || '';
const nome = $input.first().json.nome || '';
const historicoRaw = $('setarInfo1').first().json.historico || '';

let historicoTexto = '';
try {
  const msgs = JSON.parse(historicoRaw);
  if (Array.isArray(msgs) && msgs.length > 0) {
    historicoTexto = msgs.map(m => `[${m.role === 'incoming' ? 'Cliente' : 'Atendente'}]: ${m.content || ''}`).join('\n');
  }
} catch {}

let contexto = '';
if (resumo && resumo.trim()) {
  contexto = `\n\n[HISTÓRICO DO CLIENTE${nome ? ' ' + nome : ''}]\n${resumo.slice(0, 800)}\n[FIM DO HISTÓRICO]`;
}
if (historicoTexto) {
  contexto += `\n\n[ÚLTIMAS MENSAGENS DA CONVERSA]\n${historicoTexto.slice(0, 2000)}\n[FIM DO HISTÓRICO DA CONVERSA]`;
}

return [{ json: {
  mensagem_com_contexto: msg + contexto,
  cliente_nome_crm: nome
} }];

const base64 = $input.first().json.base64;
const mimetype = $input.first().json.mimetype || 'audio/ogg';
const ext = mimetype.split('/')[1]?.split(';')[0] || 'ogg';

if (!base64) throw new Error('Base64 vazio — Evolution não retornou a mídia');

return [{
  json: {},
  binary: {
    data: {
      data: base64,
      mimeType: mimetype,
      fileName: `audio.${ext}`,
      fileExtension: ext
    }
  }
}];

const days = ['domingo', 'segunda', 'terça', 'quarta', 'quinta', 'sexta', 'sábado'];
const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
let result = `Hoje é ${days[now.getDay()]} ${pad(now.getDate())}/${pad(now.getMonth()+1)}/${String(now.getFullYear()).slice(2)} às ${pad(now.getHours())}:${pad(now.getMinutes())}\n`;
for (let i = 1; i <= 6; i++) {
  const future = new Date(now);
  future.setDate(now.getDate() + i);
  let label = '';
  if (i === 1) { label = `Amanhã é ${days[future.getDay()]} ${pad(future.getDate())}/${pad(future.getMonth()+1)}/${String(future.getFullYear()).slice(2)}`; }
  else if (i === 2) { label = `Depois de amanhã é ${days[future.getDay()]} ${pad(future.getDate())}/${pad(future.getMonth()+1)}/${String(future.getFullYear()).slice(2)}`; }
  else { label = `A próxima ${days[future.getDay()]} será dia ${pad(future.getDate())}/${pad(future.getMonth()+1)}/${String(future.getFullYear()).slice(2)}`; }
  result += `${label}\n`;
}
return [{ json: { resultado: result.trim() } }];

