const mensagensTexto = $input.first().json.output || "";
if (typeof mensagensTexto !== "string" || !mensagensTexto.trim()) { return []; }

// Remove todos os emojis
const semEmojis = mensagensTexto.replace(/\p{Extended_Pictographic}/gu, '').trim();

const textoCorrigido = semEmojis.replace(/\\n/g, "\n");
const mensagensArray = textoCorrigido.split(/\n/).map(line => line.trim()).filter(line => line.length > 0);
return mensagensArray.map(msg => ({ json: { output: msg } }));
